from vex import verify, Policy

support_policy = Policy(
    name="CustomerSupport",
    rules=[
        "no_internal_ips",
        "no_credit_card_display",
        "escalate_high_value_orders"
    ]
)

@verify(
    policies=[support_policy],
    pii_filters=["email", "phone", "order_id"]
)
def protected_support(query: str, customer_id: str):
    context = crm.get_customer_context(customer_id)
    return agent.run(f"{query}\nContext: {context}")

response = protected_support("What's my refund status?", "cust_456")

from vex import verify, FactCheck

crm_fact_checker = FactCheck(
    source="zendesk_crm",
    fields=["order_status", "ticket_history"]
)

@verify(
    fact_checks=[crm_fact_checker],
    escalation_triggers=[
        "refund_amount > 1000",
        "vip_customer",
        "legal_keywords"
    ]
)
def verified_support_action(query: str):
    result = agent.run(query)
    if "escalate" in result:
        return agent.tools.escalate_to_human(result)
    return result

final_response = verified_support_action("Authorize $2500 refund")
